import{_ as s,c as n,o as a,d as p}from"./app.661b9247.js";const m=JSON.parse('{"title":"Node项目上线部署","description":"","frontmatter":{},"headers":[{"level":2,"title":"如何上线Node编写的项目?","slug":"如何上线node编写的项目","link":"#如何上线node编写的项目","children":[{"level":3,"title":"1.上线项目需要考虑的几个问题","slug":"_1-上线项目需要考虑的几个问题","link":"#_1-上线项目需要考虑的几个问题","children":[]},{"level":3,"title":"2.如何解决上述问题?","slug":"_2-如何解决上述问题","link":"#_2-如何解决上述问题","children":[]},{"level":3,"title":"3.PM2使用","slug":"_3-pm2使用","link":"#_3-pm2使用","children":[]}]}],"relativePath":"Document/Node后端框架开发/Node项目上线部署.md","lastUpdated":1671106709000}'),l={name:"Document/Node后端框架开发/Node项目上线部署.md"},e=p(`<h1 id="node项目上线部署" tabindex="-1">Node项目上线部署 <a class="header-anchor" href="#node项目上线部署" aria-hidden="true">#</a></h1><h2 id="如何上线node编写的项目" tabindex="-1">如何上线Node编写的项目? <a class="header-anchor" href="#如何上线node编写的项目" aria-hidden="true">#</a></h2><h3 id="_1-上线项目需要考虑的几个问题" tabindex="-1">1.上线项目需要考虑的几个问题 <a class="header-anchor" href="#_1-上线项目需要考虑的几个问题" aria-hidden="true">#</a></h3><ul><li><p>1.1 服务稳定性, 不会因为程序的某个错误或异常导致项目停止服务</p></li><li><p>1.2 线上日志记录, 除了记录访问日志以外, 我们还需要记录错误日志和自定义日志</p></li><li><p>1.3 充分利用服务器资源, Node是单线程的, 服务器是多核的, 一台服务器只运行一个Node程序太浪费资源</p></li></ul><h3 id="_2-如何解决上述问题" tabindex="-1">2.如何解决上述问题? <a class="header-anchor" href="#_2-如何解决上述问题" aria-hidden="true">#</a></h3><h4 id="通过pm2" tabindex="-1">通过PM2 <a class="header-anchor" href="#通过pm2" aria-hidden="true">#</a></h4><ul><li><p>2.1 PM2的进程守护可以在程序崩溃后自动重启</p></li><li><p>2.2 PM2自带日志记录的功能, 可以很方便的记录错误日志和自定义日志</p></li><li><p>2.3 PM2能够启动多个Node进程, 充分利用服务器资源</p></li></ul><h3 id="_3-pm2使用" tabindex="-1">3.PM2使用 <a class="header-anchor" href="#_3-pm2使用" aria-hidden="true">#</a></h3><p>pm2的npm文档：<a href="https://www.npmjs.com/package/pm2" target="_blank" rel="noreferrer">pm2 - npm (npmjs.com)</a></p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#7F848E;font-style:italic;"># 全局安装pm2包</span></span>
<span class="line"><span style="color:#ABB2BF;">npm </span><span style="color:#98C379;">install</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pm2</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-g</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 查看pm2版本|用来检查是否安装成功</span></span>
<span class="line"><span style="color:#ABB2BF;">pm2 </span><span style="color:#D19A66;">--version</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 在项目终端中，通过pm2运行Node项目</span></span>
<span class="line"><span style="color:#ABB2BF;">pm2 </span><span style="color:#98C379;">start</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">app.js</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h4 id="pm2常用命令" tabindex="-1">pm2常用命令 <a class="header-anchor" href="#pm2常用命令" aria-hidden="true">#</a></h4><p>appName|appId：是启动项目成功后出现的表格信息，name和id字段</p><p>如果不知道信息，可以使用罗列命令：pm2 list</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#7F848E;font-style:italic;"># 启动应用程序</span></span>
<span class="line"><span style="color:#ABB2BF;">pm2 </span><span style="color:#98C379;">start</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">app.js</span><span style="color:#ABB2BF;">|config</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 列出启动的所有的应用程序</span></span>
<span class="line"><span style="color:#ABB2BF;">pm2 </span><span style="color:#98C379;">list</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 重启应用程序</span></span>
<span class="line"><span style="color:#ABB2BF;">pm2 </span><span style="color:#98C379;">restart</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">appName</span><span style="color:#ABB2BF;">|appId</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 查看应用程序详细信息</span></span>
<span class="line"><span style="color:#ABB2BF;">pm2 </span><span style="color:#98C379;">info</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">appName</span><span style="color:#ABB2BF;">|appId</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 显示指定应用程序的日志</span></span>
<span class="line"><span style="color:#ABB2BF;">pm2 </span><span style="color:#98C379;">log</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">appName</span><span style="color:#ABB2BF;">|appId</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 监控应用程序</span></span>
<span class="line"><span style="color:#ABB2BF;">pm2 </span><span style="color:#98C379;">monit</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">appName</span><span style="color:#ABB2BF;">|appId</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 停止应用程序</span></span>
<span class="line"><span style="color:#ABB2BF;">pm2 </span><span style="color:#98C379;">stop</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">appName</span><span style="color:#ABB2BF;">|appId</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 关闭并删除所有应用</span></span>
<span class="line"><span style="color:#ABB2BF;">pm2 </span><span style="color:#98C379;">delete</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">appName</span><span style="color:#ABB2BF;">|appId</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><h4 id="pm2日志相关命令" tabindex="-1">pm2日志相关命令 <a class="header-anchor" href="#pm2日志相关命令" aria-hidden="true">#</a></h4><p>pm2 log appName|appId 日志命令：打印的是以下日志，两种日志信息</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#7F848E;font-style:italic;">// 如果是通过pm2来启动Node项目, 那么会自动将log输出的内容记录到自定义日志当中</span></span>
<span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;接收到请求&#39;</span><span style="color:#ABB2BF;">); </span><span style="color:#7F848E;font-style:italic;">// 自定义日志</span></span>
<span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">error</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;我是错误日志&#39;</span><span style="color:#ABB2BF;">); </span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>监控应用程序命令：pm2 monit appName|appId</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;">会实时显示应用程序状态和日志等</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="pm2进程守护" tabindex="-1">PM2进程守护 <a class="header-anchor" href="#pm2进程守护" aria-hidden="true">#</a></h4><p>自定义错误抛出路由，测试：/error</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#C678DD;">if</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">path</span><span style="color:#ABB2BF;"> </span><span style="color:#56B6C2;">===</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">&#39;/error&#39;</span><span style="color:#ABB2BF;">){</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#C678DD;">throw</span><span style="color:#ABB2BF;"> </span><span style="color:#C678DD;">new</span><span style="color:#ABB2BF;"> </span><span style="color:#61AFEF;">Error</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;故意抛出异常, 引发程序的崩溃&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>项目抛出异常后会自动重启，达到进程守护的作用</p><h4 id="pm2常用node项目配置😍" tabindex="-1">PM2常用Node项目配置😍 <a class="header-anchor" href="#pm2常用node项目配置😍" aria-hidden="true">#</a></h4><h5 id="在需要运行的node项目根目录中-新建pm2配置文件-pm2-conf-json" tabindex="-1">在需要运行的Node项目根目录中，新建pm2配置文件：<code>pm2.conf.json</code> <a class="header-anchor" href="#在需要运行的node项目根目录中-新建pm2配置文件-pm2-conf-json" aria-hidden="true">#</a></h5><div class="language-json line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#E06C75;">&quot;apps&quot;</span><span style="color:#ABB2BF;">:{</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;name&quot;</span><span style="color:#ABB2BF;">:</span><span style="color:#98C379;">&quot;应用程序名称，如:node-server&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;script&quot;</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&quot;入口文件名称，如:app.js&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;watch&quot;</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">true</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;ignore_watch&quot;</span><span style="color:#ABB2BF;">: [</span></span>
<span class="line"><span style="color:#ABB2BF;">      </span><span style="color:#98C379;">&quot;node_modules&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">      </span><span style="color:#98C379;">&quot;logs&quot;</span></span>
<span class="line"><span style="color:#ABB2BF;">    ],</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;error_file&quot;</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&quot;logs/错误日志文件名称，如:error.log&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;out_file&quot;</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&quot;logs/自定义日志文件名称，如:custom.log&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;log_date_format&quot;</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&quot;yyyy-MM-dd HH:mm:ss&quot;</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><h5 id="通过运行pm2配置文件-pm2-conf-json-来启动项目" tabindex="-1">通过运行pm2配置文件(pm2.conf.json)来启动项目 <a class="header-anchor" href="#通过运行pm2配置文件-pm2-conf-json-来启动项目" aria-hidden="true">#</a></h5><p>可以在package.json里配置script命令</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;">pm2 </span><span style="color:#98C379;">start</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pm2.conf.json</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="pm2配置-负载均衡-多线程" tabindex="-1">PM2配置：负载均衡-多线程 <a class="header-anchor" href="#pm2配置-负载均衡-多线程" aria-hidden="true">#</a></h4><p>在需要运行的Node项目根目录中，新建pm2配置文件：<code>pm2.conf.json</code></p><p>原有的配置中添加配置，CPU是多少核的服务器：&quot;instances&quot;: 4</p><div class="language-json line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#E06C75;">&quot;apps&quot;</span><span style="color:#ABB2BF;">:{</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;name&quot;</span><span style="color:#ABB2BF;">:</span><span style="color:#98C379;">&quot;应用程序名称，如:node-server&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;script&quot;</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&quot;入口文件名称，如:app.js&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;watch&quot;</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">true</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;ignore_watch&quot;</span><span style="color:#ABB2BF;">: [</span></span>
<span class="line"><span style="color:#ABB2BF;">      </span><span style="color:#98C379;">&quot;node_modules&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">      </span><span style="color:#98C379;">&quot;logs&quot;</span></span>
<span class="line"><span style="color:#ABB2BF;">    ],</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;error_file&quot;</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&quot;logs/错误日志文件名称，如:error.log&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;out_file&quot;</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&quot;logs/自定义日志文件名称，如:custom.log&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;log_date_format&quot;</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&quot;yyyy-MM-dd HH:mm:ss&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#E06C75;">&quot;instances&quot;</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">4</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><p>再启动运行项目：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;">pm2 </span><span style="color:#98C379;">start</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pm2.conf.json</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>运行成功后，会启动4个进程，都是一个项目名字，前端访问，会随机分配一个服务器进程</p><h1 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a></h1>`,37),o=[e];function r(c,t,i,B,d,y){return a(),n("div",null,o)}const b=s(l,[["render",r]]);export{m as __pageData,b as default};
